""" Integration tests for Chat Session Repository.
Tests the ChatSessionRepository implementation against the ChatSessionRepositoryInterface. """
import pytest from uuid import uuid4
from src.database.models import ChatSession from src.database.repository.sqlalchemy import ChatSessionRepository from src.database.repository.interfaces.chat_session_repository import ( ChatSessionSearchCriteria, UpdatedChatSessionData, )
@pytest.fixture async def chat_session_repo(db_connection): """Provide a ChatSessionRepository instance.""" return ChatSessionRepository(connection=db_connection)
@pytest.fixture async def cleanup_sessions(db_connection): """Cleanup test chat sessions after each test.""" yield from sqlalchemy import delete
async with db_connection.get_session() as session: await session.execute(delete(ChatSession)) await session.commit()
class TestChatSessionRepositoryCore: """Core CRUD functionality tests."""
@pytest.mark.asyncio async def test_create_session_success( self, chat_session_repo, test_user, cleanup_sessions ): """Test successful chat session creation.""" session = ChatSession(id=uuid4(), user_id=test_user.id)
session_id = await chat_session_repo.create(session)
assert session_id is not None assert session_id == session.id
@pytest.mark.asyncio async def test_get_by_id_success( self, chat_session_repo, test_user, cleanup_sessions ): """Test retrieving a chat session by ID.""" session = ChatSession(id=uuid4(), user_id=test_user.id) await chat_session_repo.create(session)
retrieved = await chat_session_repo.get_by_id(session.id)
assert retrieved is not None assert retrieved.id == session.id assert retrieved.user_id == test_user.id
@pytest.mark.asyncio async def test_get_by_id_not_found(self, chat_session_repo, cleanup_sessions): """Test retrieving non-existent session returns None.""" fake_id = uuid4()
result = await chat_session_repo.get_by_id(fake_id)
assert result is None
@pytest.mark.asyncio async def test_list_by_id(self, chat_session_repo, test_user, cleanup_sessions): """Test listing sessions by ID.""" session = ChatSession(id=uuid4(), user_id=test_user.id) await chat_session_repo.create(session)
criteria = ChatSessionSearchCriteria(id=session.id) results = await chat_session_repo.list_by(criteria)
assert len(results) >= 1 assert any(s.id == session.id for s in results)
@pytest.mark.asyncio async def test_list_by_no_criteria( self, chat_session_repo, test_user, cleanup_sessions ): """Test listing all sessions without criteria.""" for i in range(3): session = ChatSession(id=uuid4(), user_id=test_user.id) await chat_session_repo.create(session)
results = await chat_session_repo.list_by()
assert len(results) == 3
@pytest.mark.asyncio async def test_update_session_title( self, chat_session_repo, test_user, cleanup_sessions ): """Test updating session title.""" session = ChatSession(id=uuid4(), user_id=test_user.id, title="Old Title") await chat_session_repo.create(session)
update_data = UpdatedChatSessionData(title="New Title") updated = await chat_session_repo.update(session.id, update_data)
assert updated is not None assert updated.title == "New Title"
